VALUES
  ('elementary-f29af906-moex-00748', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '關於公辦市地重劃之敘述，下列何者錯誤？', '["市地重劃之辦理，屬多階段行政程序", "重劃後實際分配土地面積多於應分配之面積者，應繳納差額地價", "重劃分配結果公告之性質屬事實行為", "重劃前已有合法建築物之土地，其建築物不妨礙都市計畫、重劃工程及土地分配者，按原有位置分配之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00749', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依都市計畫法第79條規定，都市計畫範圍內土地或建築物之使用，違反該法或內政部、直轄市、縣（市） 政府依該法所發布之命令者，當地地方政府或鄉、鎮、縣轄市公所得處其土地或建築物所有權人、使用 人或管理人新臺幣多少元罰鍰？', '["3萬元以上10萬元以下", "5萬元以上20萬元以下", "6萬元以上30萬元以下", "10萬元以上60萬元以下"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00750', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依都市計畫法規定，應報請備案之主要計畫，非經准予備案，不得發布實施。但備案機關於文到後幾日 內不為准否之指示者，視為准予備案？', '["7日", "10日", "20日", "30日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00751', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '下列有關地價指數表之編製規定，何者錯誤？', '["由內政部編製", "編製內容為都市土地商業區、住宅區、工業區、農業區之地價", "每年編製地價指數表2次", "依直轄市或縣（市）地政機關調查之地價編製"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00752', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依租賃住宅市場發展及管理條例之規定，下列有關非具有消費關係之租賃契約，其應約定、不得約定事 項之敘述，何者錯誤？', '["不得約定限制或免除租賃當事人之一方義務或責任", "不得約定限制或剝奪租賃當事人之一方行使權利，及加重其義務或責任", "非具有消費關係之租賃契約條款，違反應約定及不得約定事項者，無效", "非具有消費關係之租賃契約條款，該應約定事項未記載於契約者，不構成契約之內容"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00753', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '規定地價後，每幾年重新規定地價一次；但必要時，得由下列何者延長之？', '["3年；直轄市或縣（市）地政機關", "3年；直轄市或縣（市）政府地價及標準地價評議委員會", "2年；財政部", "2年；內政部"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00754', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '有關申請不動產估價師登記開業之敘述，下列何者錯誤？', '["領有不動產估價師證書", "應先加入不動產估價師公會", "實際從事估價業務達2年以上之估價經驗", "向所在地直轄市或縣（市）主管機關申請"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00755', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '下列何者非屬地價及標準地價評議委員會之評議事項？', '["地價區段劃分", "協議價購召開", "土地改良物價額", "市地重劃前後地價"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00756', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依司法院釋字第 731 號解釋意旨，實施區段徵收時，原土地所有權人申請發給抵價地之期間，應如何計 算？', '["以核定區段徵收之日起算30日", "以區段徵收公告之翌日起算30日", "以區段徵收公告期滿之翌日起算30日", "以區段徵收書面通知送達原土地所有權人之翌日起算30日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
